int getDistancia(const string& origem, const string& destino, char tipoTransporte) {
    // Se for transporte Aéreo 'A', busca na tabela nova que criamos
    if (tipoTransporte == 'A' || tipoTransporte == 'a') {
        auto itOrigem = distanciasAereas.find(origem);
        if (itOrigem != distanciasAereas.end()) {
            auto itDestino = itOrigem->second.find(destino);
            if (itDestino != itOrigem->second.end()) {
                return itDestino->second;
            }
        }
    } 
    // Caso contrário (Terrestre 'T' ou qualquer outro), busca na tabela original
    else {
        auto itOrigem = distancias.find(origem);
        if (itOrigem != distancias.end()) {
            auto itDestino = itOrigem->second.find(destino);
            if (itDestino != itOrigem->second.end()) {
                return itDestino->second;
            }
        }
    }
    return -1; // Rota não encontrada
}

char getTipoTrajetoNecessario(const string &origem, const string &destino)
{
    if (origem == destino)
        return 'T';
    int dist = getDistancia(origem, destino, 'T');
    if (dist == 0)
    {
        return 'A'; // Deslocamento 0 entre cidades diferentes = Rota puramente Aérea
    }
    return 'T'; // Demais caminhos possuem malha Terrestre padrão
}